// ===== MULTI-FILE SCHEMA CONFIGURATION =====
// This is the main schema file that references all other schema files
// Prisma automatically discovers and includes all .prisma files in the same directory

generator client {
  provider        = "prisma-client-js"
  previewFeatures = ["queryCompiler", "driverAdapters"]
  output          = "../generated/prisma"
  engineType      = "library"
  binaryTargets   = []
}

datasource db {
  provider = "sqlite"
  url      = env("DATABASE_URL") // Use environment variable for flexibility
}

// All models are now organized in separate files in the same directory:
// - workflow-enums.prisma - All enums
// - task-models.prisma - Core task management models  
// - rule-models.prisma - Intelligent workflow rules system
// - onboarding-models.prisma - Project onboarding system

// Prisma automatically includes all .prisma files in the same directory

// ===== WORKFLOW SYSTEM ENUMS =====
// All enums used throughout the workflow system

// Streamlined enums for workflow rules system
enum StepType {
  ACTION // Perform an action (git operations, file operations, MCP calls)
  ANALYSIS // Analyze or validate (codebase analysis, quality checks)
}

enum StepProgressStatus {
  NOT_STARTED
  IN_PROGRESS
  COMPLETED
  SKIPPED
  FAILED
}

// 🆕 NEW: Step execution result for MCP-focused tracking
enum StepExecutionResult {
  SUCCESS
  FAILURE
}

enum ProjectType {
  MONOREPO
  MICROSERVICES
  SINGLE_APP
  LIBRARY
  PLUGIN
  FRAMEWORK
  CLI_TOOL
  API_SERVICE
  FRONTEND_APP
  FULLSTACK_APP
}

enum PatternType {
  ARCHITECTURAL
  CODE_STYLE
  TESTING
  DEPLOYMENT
  SECURITY
  PERFORMANCE
  DATA_ACCESS
  ERROR_HANDLING
  VALIDATION
  DOCUMENTATION
}

// Enums for Project Onboarding System
enum OnboardingStatus {
  PENDING
  IN_PROGRESS
  COMPLETED
  FAILED
  NEEDS_UPDATE
}

enum AnalysisRequestType {
  INITIAL_ANALYSIS
  ARCHITECTURE_DEEP_DIVE
  CODE_PATTERN_ANALYSIS
  QUALITY_ASSESSMENT
  INTEGRATION_ANALYSIS
  ROLE_CONTEXT_GENERATION
  PATTERN_EXTRACTION
  TECHNICAL_DEBT_ANALYSIS
}

enum ProcessingStatus {
  PENDING
  IN_PROGRESS
  COMPLETED
  FAILED
  RETRY_NEEDED
}

enum WorkflowExecutionMode {
  GUIDED // Step-by-step guided execution with user interaction
  AUTOMATED // Fully automated execution without user intervention
  HYBRID // Mix of automated and guided steps based on context
}

